
import re
CARDS_PATH = '/Users/radekmajewski/Downloads/valujack/public/cards.js'
descriptions = {
    663: ('Aramis Group SA', 'French online used car retailer. High growth.', 'Online used car marketplace.', "Aramis Group is a French online used car retailer operating across France, Belgium, Spain, and the UK. The company buys, refurbishes, and sells used cars through digital channels — benefiting from structural shift of used car purchasing to online platforms.", 'Online used cars. High growth recovery.', 'Used car platform recovery.', "A French online used car retailer with a 7.0% ROIC and EPS growth of 77.0% annualised from a low base. Aramis Group operates a digital used car platform across Europe — recovering strongly as consumer confidence and used car demand normalise.", ["Online used car buying, refurbishing and selling across France, Belgium, Spain and UK.", "ROIC of 7.0% with improving trajectory as used car platform scales.", "EPS grew 77.0% annualised as used car demand and platform efficiency improved.", "Revenue grew 6.3% annualised with consistent used car volume growth across European markets."]),
    664: ('Azelis Group NV', 'Belgian specialty chemicals distributor. Contrarian recovery.', 'Specialty chemicals distribution.', "Azelis is a Belgian specialty chemicals and food ingredients distributor operating across Europe, Asia, and the Americas. The company has been beaten down as specialty chemical distribution margins compressed — fundamentals remain intact while the stock trades below fair value.", 'Specialty chemicals. Contrarian recovery.', 'Chemical distribution recovery.', "A Belgian specialty chemicals distributor with a 2.5% ROIC in a recovery phase as specialty chemical distribution margins normalise. Azelis global network distributes specialty ingredients and chemicals — quality distribution business at a contrarian entry point.", ["Specialty chemicals and food ingredients distribution across Europe, Asia and Americas.", "Global distribution network with deep customer and supplier relationships.", "Recovery play as specialty chemical distribution margins normalise from compressed levels.", "EPS growing 8.7% annualised as distribution volumes and margins recover."]),
    665: ('Baltic Classifieds Group PLC', 'Baltic online classifieds platform. High growth.', 'Baltic classifieds monopoly.', "Baltic Classifieds Group operates dominant online classified platforms across Estonia, Latvia, and Lithuania — covering real estate, cars, and jobs. The company holds near-monopoly positions in each Baltic market with strong network effects.", 'Baltic classifieds monopoly. High growth.', 'Baltic digital monopoly compounder.', "A UK-listed Baltic classifieds monopoly with a 14.7% ROIC and EPS growth of 248.9% annualised from a low base. Baltic Classifieds holds dominant positions in Estonian, Latvian, and Lithuanian online classifieds — network effects create near-impenetrable market positions.", ["Dominant online classifieds for real estate, cars and jobs across Estonia, Latvia and Lithuania.", "Near-monopoly positions with strong network effects in each Baltic market.", "EPS grew 248.9% annualised as Baltic digital advertising and listing revenues expanded.", "Revenue grew 9.9% annualised with consistent Baltic market monetisation improvement."]),
    666: ('Barrett Business Services Inc', 'US professional employer organisation. High ROIC.', 'US PEO services leader.', "Barrett Business Services is a US professional employer organisation providing HR, payroll, benefits, and workers compensation services to small and medium businesses. The company takes on co-employer status — managing HR complexity for SMBs who lack internal HR capabilities.", 'US PEO services. High ROIC compounder.', 'HR outsourcing compounder.', "A US professional employer organisation with a 25.2% ROIC and EPS growth of 13.8% annualised. Barrett Business Services manages HR, payroll, and benefits for SMBs — a sticky, recurring service business with high switching costs from deep payroll and HR integration.", ["HR, payroll, benefits and workers compensation services for US small and medium businesses.", "ROIC of 25.2% reflects strong returns from sticky HR outsourcing relationships.", "EPS grew 13.8% annualised with consistent SMB demand for HR outsourcing services.", "Revenue grew 8.4% annualised as SMB HR complexity drives professional employer adoption."]),
    667: ('Bilendi SA', 'French market research technology. High growth.', 'Market research tech platform.', "Bilendi is a French market research technology company providing online panel and survey solutions to research agencies and brands across Europe. The company operates consumer panels used by market research firms for data collection and consumer insights.", 'Market research tech. High growth.', 'Research technology compounder.', "A French market research technology company with a 4.9% ROIC and EPS growth of 17.6% annualised. Bilendi operates consumer research panels across Europe — providing online survey infrastructure to market research agencies and brand insights teams.", ["Online consumer panels and survey solutions for market research agencies and brands.", "EPS grew 17.6% annualised as European market research demand and panel adoption grew.", "Revenue grew 21.2% annualised with consistent geographic and product expansion.", "Growing demand for consumer insights driving research technology platform adoption."]),
    668: ('Bonesupport', 'Swedish bone graft substitute. High ROIC.', 'Bone graft substitute specialist.', "Bonesupport is a Swedish medical technology company producing CERAMENT — a injectable bone graft substitute that fills bone voids and delivers antibiotics directly to infection sites. The product is used in orthopaedic surgery to treat bone defects and bone infections.", 'Bone graft substitute. High ROIC growth.', 'Orthopaedic technology compounder.', "A Swedish bone graft company with a 28.8% ROIC and EPS growth of 26.6% annualised. Bonesupport CERAMENT fills bone voids and delivers local antibiotics — a clinically superior product gaining rapid adoption in orthopaedic surgery for bone defect treatment.", ["CERAMENT injectable bone graft substitute for bone void filling and infection treatment.", "ROIC of 28.8% — strong returns from a proprietary orthopaedic biomaterial.", "EPS grew 26.6% annualised as CERAMENT adoption in orthopaedic surgery accelerated.", "Revenue grew 30.7% annualised as clinical evidence and surgeon adoption expanded."]),
    669: ('Booz Allen Hamilton Holding Corp', 'US defence consulting giant. High ROIC.', 'US defence consulting leader.', "Booz Allen Hamilton is a US management and technology consulting firm serving US government and defence clients. The company provides strategy, analytics, and technology services to virtually every major US government agency — a deeply embedded government partner.", 'US defence consulting. High ROIC.', 'Government consulting compounder.', "A US defence and government consulting company with an 18.8% ROIC and EPS growth of 9.0% annualised. Booz Allen Hamilton serves virtually every major US government agency — deeply embedded relationships with mission-critical consulting and technology services.", ["Management and technology consulting for US government and defence agencies.", "ROIC of 18.8% reflects consistent returns from deeply embedded government relationships.", "EPS grew 9.0% annualised with consistent US government technology spending.", "Long-term contract backlog provides multi-year revenue visibility."]),
    670: ('BTS Group', 'Swedish business simulation training. High ROIC.', 'Business simulation training.', "BTS Group is a Swedish company providing business simulation and experiential learning programmes to global corporations. The company creates custom business simulations that help executives and managers practice strategic decision-making in realistic scenarios.", 'Business simulations. High ROIC growth.', 'Corporate training compounder.', "A Swedish business simulation training company with an 8.1% ROIC and EPS growth of 30.5% annualised. BTS Group creates custom simulations for Fortune 500 companies — sticky, recurring training relationships with high-quality corporate clients.", ["Custom business simulations and experiential learning for global corporations.", "EPS grew 30.5% annualised as corporate simulation training demand expanded.", "Revenue recovering as corporate training investment normalises post-pandemic.", "Sticky client relationships with Fortune 500 companies drive recurring programme revenue."]),
    671: ('Cars.com Inc', 'US automotive digital marketplace. Contrarian recovery.', 'Automotive digital marketplace.', "Cars.com is a US digital automotive marketplace connecting car buyers with dealers across the country. The company has been beaten down as automotive inventory normalised from COVID scarcity — fundamentals remain sound while the stock trades below fair value.", 'Automotive marketplace. Contrarian recovery.', 'Auto marketplace recovery.', "A US automotive digital marketplace with a 2.2% ROIC recovering as automotive inventory and dealer advertising normalise. Cars.com connects buyers with dealers — quality digital marketplace at a contrarian entry point as the automotive cycle recovers.", ["Digital automotive marketplace connecting car buyers with dealers across the US.", "Recovery play as automotive inventory and dealer digital advertising spending normalises.", "EPS grew 15.2% annualised as marketplace traffic and dealer monetisation improved.", "Revenue growing 0.6% annualised with stabilising dealer subscription and advertising revenue."]),
    672: ('CGI Inc', 'Canadian IT services giant. Quality compounder.', 'IT services quality compounder.', "CGI is a Canadian IT services company providing consulting, systems integration, and managed services to government and enterprise clients globally. The company has a long track record of disciplined acquisitions and organic growth — compounding revenue and earnings consistently.", 'IT services. Quality compounder.', 'Canadian IT compounder.', "A Canadian IT services company with a 12.6% ROIC and EPS growth of 6.5% annualised. CGI provides consulting and managed IT services to government and enterprise — a financially sound, disciplined acquirer with consistent long-term compounding.", ["IT consulting, systems integration and managed services for government and enterprise.", "ROIC of 12.6% reflects consistent returns from disciplined IT services operations.", "EPS grew 6.5% annualised with consistent organic growth and disciplined acquisitions.", "Revenue grew 9.1% annualised as IT outsourcing demand and acquisition integration expanded."]),
    673: ('Computer Modelling Group Ltd', 'Canadian reservoir simulation software. High ROIC.', 'Reservoir simulation specialist.', "Computer Modelling Group produces reservoir simulation software used by oil and gas companies to model subsurface reservoirs and optimise production. The company has a dominant position in reservoir simulation — a niche software with high switching costs from deep technical integration.", 'Reservoir simulation software. High ROIC.', 'Niche software compounder.', "A Canadian reservoir simulation software company with a 14.9% ROIC and consistent recurring revenue from oil and gas producers globally. Computer Modelling Group software is deeply embedded in reservoir engineering workflows — high switching costs and recurring subscription revenue.", ["Reservoir simulation software for oil and gas field development and production optimisation.", "ROIC of 14.9% reflects strong returns from a dominant niche simulation software position.", "Deep technical integration creates high switching costs and recurring subscription revenue.", "Consistent demand from global oil and gas companies requiring reservoir modelling."]),
    674: ('Corcept Therapeutics Inc', 'US cortisol modulation pharma. High ROIC.', 'Cortisol pharma specialist.', "Corcept Therapeutics is a US pharmaceutical company focused on cortisol modulation — producing Korlym for Cushing syndrome and developing new cortisol modulator drugs. The company has a growing pipeline of cortisol modulators for oncology and other conditions.", 'Cortisol modulation. High ROIC compounder.', 'Specialty pharma compounder.', "A US cortisol modulation pharmaceutical company with a 33.4% ROIC. Corcept Korlym treats Cushing syndrome — a rare cortisol disorder — while a pipeline of new cortisol modulators targets oncology applications. Strong financial health with consistent prescription revenue.", ["Korlym for Cushing syndrome and cortisol modulator pipeline for oncology applications.", "ROIC of 33.4% reflects strong returns from established rare disease drug franchise.", "Revenue growing 12.8% annualised as Korlym prescriptions and new indications expand.", "Growing cortisol modulator pipeline targeting large oncology applications."]),
    675: ('Delcath Systems Inc', 'US hepatic artery infusion devices. High growth.', 'Liver cancer treatment device.', "Delcath Systems produces HEPZATO KIT — a chemosaturation system for delivering high-dose chemotherapy directly to the liver. The FDA-approved device treats hepatic metastases from uveal melanoma — a rare liver cancer with limited treatment options.", 'Liver cancer device. High growth.', 'Oncology device compounder.', "A US liver cancer treatment company with a 12.5% ROIC and exceptional revenue growth of 129.1% annualised from HEPZATO KIT launches. Delcath Systems FDA-approved chemosaturation device treats liver metastases — high growth from a rare disease device with no comparable alternatives.", ["HEPZATO KIT chemosaturation system for hepatic delivery of chemotherapy.", "Revenue grew 129.1% annualised as HEPZATO KIT commercial launch accelerated.", "FDA-approved device for uveal melanoma liver metastases — no comparable alternatives.", "EPS grew 15.0% annualised as device adoption expanded in academic medical centres."]),
    676: ('DXC Technology Co', 'US IT services. Contrarian recovery.', 'IT services contrarian play.', "DXC Technology is a US IT services company providing digital transformation, cloud, and managed services to global enterprises. The company has been significantly beaten down — trading below fair value as market concerns about revenue decline overshadow improving fundamentals.", 'IT services. Contrarian recovery.', 'IT services turnaround play.', "A US IT services company with a 5.6% ROIC in a contrarian recovery phase. DXC Technology provides cloud and managed IT services to global enterprises — trading at a discount to fair value with improving operational metrics and margin recovery underway.", ["Digital transformation, cloud and managed IT services for global enterprise clients.", "ROIC of 5.6% with improving trajectory as operational restructuring takes effect.", "EPS grew 43.1% annualised as cost restructuring and margin improvement progressed.", "Contrarian opportunity as market discounts overstates revenue normalisation risk."]),
    677: ('Edreams Odigeo SA', 'Spanish online travel subscription. High ROIC.', 'Online travel subscription leader.', "eDreams ODIGEO is a Spanish online travel company pioneering a subscription model for flight booking. The company Prime subscription offers members discounted flights and travel perks — building predictable recurring revenue in the traditionally transactional online travel market.", 'Online travel subscription. High ROIC.', 'Travel subscription compounder.', "A Spanish online travel company with a 13.7% ROIC and EPS growth of 21.2% annualised transitioning to a subscription model. eDreams Prime subscription has attracted millions of members — building predictable recurring revenue in a structurally growing online travel market.", ["Online flight and travel booking with Prime subscription model for frequent travellers.", "ROIC of 13.7% reflects strong returns from subscription model transition.", "EPS grew 21.2% annualised as Prime membership and recurring revenue expanded.", "Revenue grew 3.9% annualised as subscription model provides more predictable income base."]),
    678: ('Elevance Health Inc', 'US health insurance giant. Contrarian recovery.', 'US health insurance leader.', "Elevance Health is one of the largest US health insurance companies, operating Blue Cross Blue Shield plans across 14 states. The company has been beaten down as Medicaid membership declined and medical cost trends elevated — fundamentals remain sound for a recovery.", 'US health insurance. Contrarian recovery.', 'Health insurance recovery.', "A major US health insurance company with a 4.7% ROIC in a contrarian recovery phase. Elevance Health Blue Cross Blue Shield plans serve millions of Americans — high-quality insurance franchise trading below fair value as Medicaid transition and cost headwinds normalise.", ["Blue Cross Blue Shield health insurance plans across 14 US states.", "High-quality insurance franchise with millions of commercial and government plan members.", "Contrarian entry as Medicaid membership normalisation and medical cost trends stabilise.", "EPS growing 6.8% annualised as commercial membership and pricing recover."]),
    679: ('Engcon', 'Swedish tiltrotator excavator attachment. High ROIC.', 'Tiltrotator market leader.', "Engcon is a Swedish manufacturer of tiltrotators — robotic excavator attachments that allow 360-degree bucket rotation. The company pioneered the tiltrotator category and holds a dominant global market position in this high-value excavator productivity tool.", 'Tiltrotator pioneer. High ROIC.', 'Excavator technology compounder.', "A Swedish tiltrotator manufacturer with a 28.3% ROIC and growing adoption of its revolutionary excavator attachment. Engcon tiltrotators transform excavator productivity — a market-creating product with dominant global position and accelerating construction industry adoption.", ["Tiltrotators and excavator attachments for the global construction industry.", "ROIC of 28.3% reflects strong returns from pioneering the tiltrotator category.", "Revenue grew 14.6% annualised as tiltrotator adoption expanded globally.", "Dominant market position in a category Engcon created — exceptional switching costs."]),
    680: ('Eviso SpA', 'Italian energy retail. Exceptional ROIC.', 'Italian energy retail specialist.', "Eviso is an Italian energy retailer providing electricity and gas to residential and business customers. The company has generated exceptional returns on capital from its energy retail operations in the Italian liberalised energy market.", 'Italian energy retail. Exceptional ROIC.', 'Energy retail compounder.', "An Italian energy retailer with a 965.7% ROIC from highly capital-efficient energy retail operations. Eviso provides electricity and gas to Italian customers — exceptional capital efficiency from an asset-light energy retail model in a liberalised market.", ["Electricity and gas retail to residential and business customers in Italy.", "ROIC of 965.7% — extraordinary returns from an asset-light energy retail model.", "EPS grew 28.6% annualised as customer base and energy retail margins expanded.", "Revenue grew 5.8% annualised with consistent Italian energy customer growth."]),
    681: ('FactSet Research Systems Inc', 'US financial data platform. High ROIC.', 'Financial data platform leader.', "FactSet provides financial data, analytics, and workflow solutions to investment professionals globally. The company serves buy-side and sell-side institutions with integrated data and portfolio analytics — a sticky enterprise SaaS business with high switching costs.", 'Financial data platform. High ROIC.', 'Financial data compounder.', "A US financial data platform with a 17.1% ROIC and EPS growth of 8.2% annualised. FactSet provides integrated financial data and analytics to investment professionals — deeply embedded in investment workflows creating high switching costs and consistent subscription renewal.", ["Financial data, analytics and workflow solutions for buy-side and sell-side institutions.", "ROIC of 17.1% reflects consistent returns from deeply embedded financial data platform.", "EPS grew 8.2% annualised with consistent subscription renewal and new client additions.", "Revenue grew 6.5% annualised as financial data demand and platform expansion continued."]),
    682: ('Fenix Outdoor', 'Swedish outdoor gear holding. Contrarian recovery.', 'Outdoor gear brand recovery.', "Fenix Outdoor owns Fjallraven, Tierra, and other outdoor brands serving the premium outdoor apparel and equipment market. The company has been beaten down as post-COVID outdoor spending normalised — fundamentals remain solid for a premium outdoor brand portfolio.", 'Outdoor brands. Contrarian recovery.', 'Premium outdoor brand recovery.', "A Swedish outdoor brand holding company in a contrarian recovery phase as post-COVID outdoor spending normalises. Fenix Outdoor owns Fjallraven and other premium outdoor brands — quality brand portfolio trading below fair value as the market cycle normalises.", ["Fjallraven and Tierra outdoor apparel and equipment brands — premium positioning.", "Recovery play as post-COVID outdoor gear demand normalisation completes.", "Premium outdoor brand portfolio with loyal consumer following and strong retail presence.", "Contrarian entry as market discounts temporary post-pandemic demand normalisation."]),
    683: ('Fractal Gaming', 'Swedish PC case and cooling. Growth recovery.', 'PC hardware design recovery.', "Fractal Gaming designs premium PC cases, cooling, and power supply units for PC builders globally. The company has a strong brand in the PC enthusiast market — selling premium, design-focused PC hardware components through retail and direct channels.", 'PC hardware design. Growth recovery.', 'PC component brand recovery.', "A Swedish PC hardware brand with an 8.0% ROIC recovering as PC gaming and building demand normalises. Fractal Gaming designs premium PC cases and cooling components — quality brand at a contrarian entry as the PC building cycle recovers.", ["Premium PC cases, cooling and power supply units for PC builders globally.", "ROIC of 8.0% with recovering trajectory as PC building demand normalises.", "Revenue grew 16.0% annualised as PC enthusiast hardware demand and new products expanded.", "Premium design positioning with loyal PC builder community and strong brand recognition."]),
    684: ('Freshworks Inc', 'US customer and IT service software. High ROIC.', 'SMB SaaS platform compounder.', "Freshworks provides cloud-based customer support, IT service management, and CRM software targeted at small and medium businesses. The company is growing rapidly as SMBs adopt affordable, easy-to-deploy software for customer and IT service management.", 'SMB SaaS platform. High ROIC growth.', 'SMB software compounder.', "A US SMB-focused SaaS company with a 56.8% ROIC and EPS growth of 25.1% annualised. Freshworks provides customer support and IT service software to SMBs — an asset-light SaaS model with exceptional capital efficiency from a rapidly growing subscription base.", ["Customer support, IT service management and CRM software for small and medium businesses.", "ROIC of 56.8% — exceptional returns from an asset-light SMB SaaS platform.", "EPS grew 25.1% annualised as SMB software adoption and subscription revenue expanded.", "Revenue grew 16.4% annualised with consistent customer additions and ARPU expansion."]),
    685: ('HighPeak Energy Inc', 'US Permian Basin oil producer. Contrarian recovery.', 'Permian oil contrarian play.', "HighPeak Energy is a US oil producer operating in the Flat Top area of the Midland Basin, Texas. The company has been beaten down on oil price concerns — fundamentals remain sound with low-cost Permian production and a strong asset base trading below fair value.", 'Permian oil. Contrarian recovery.', 'Permian oil recovery play.', "A US Permian Basin oil producer in a contrarian recovery phase. HighPeak Energy operates low-cost Midland Basin wells — quality oil assets trading below fair value as the market discounts oil price uncertainty.", ["Oil production from the Flat Top area of the Midland Basin, Texas.", "Low-cost Permian Basin production with strong per-well economics.", "EPS grew 24.8% annualised as production volumes and well efficiency improved.", "Contrarian entry as Permian oil assets trade below intrinsic value on oil price concerns."]),
    686: ('Hikma Pharmaceuticals PLC', 'UK generic and branded pharma. Contrarian recovery.', 'Generic pharma contrarian play.', "Hikma Pharmaceuticals is a UK generic and branded pharmaceutical company serving the US, Middle East, and North Africa markets. The company has been beaten down on generic drug pricing pressure — fundamentals remain solid with improving MENA branded business and US generic recovery.", 'Generic pharma. Contrarian recovery.', 'Pharma contrarian recovery.', "A UK generic and branded pharmaceutical company with a 10.1% ROIC in a contrarian recovery phase. Hikma serves US generic and MENA branded pharmaceutical markets — quality pharma franchise trading below fair value as generic pricing headwinds normalise.", ["Generic and branded pharmaceuticals across US, Middle East and North Africa markets.", "ROIC of 10.1% with improving trajectory as generic pricing and MENA branded business recover.", "Revenue grew 7.1% annualised with consistent MENA branded and US generic sales.", "Contrarian entry as generic drug pricing concerns overstated relative to business fundamentals."]),
    688: ('HP Inc', 'US PC and printer giant. Contrarian recovery.', 'PC and printer contrarian play.', "HP Inc is the US manufacturer of personal computers and printers — selling consumer and commercial PCs under the HP and Omen brands alongside inkjet and laser printers. The company has been beaten down as PC demand normalised from pandemic highs.", 'PC and printers. Contrarian recovery.', 'PC hardware recovery.', "A US PC and printer manufacturer with a 27.6% ROIC in a contrarian recovery phase. HP Inc produces PCs and printers for consumers and businesses — quality hardware franchise trading below fair value as post-pandemic PC demand normalisation completes.", ["Personal computers and printers for consumer and commercial markets globally.", "ROIC of 27.6% reflects strong returns from established PC and printer franchises.", "EPS improving as post-pandemic PC demand normalisation completes.", "Contrarian entry as market discounts temporary PC unit volume normalisation."]),
    690: ('Icon PLC', 'Irish clinical research organisation. Quality compounder.', 'Clinical research compounder.', "Icon is an Irish contract research organisation providing clinical trial management, data management, and regulatory services to pharmaceutical and biotech companies. The company is one of the largest CROs globally — serving the structural growth in drug development outsourcing.", 'Clinical research. Quality compounder.', 'CRO quality compounder.', "An Irish clinical research organisation with a 4.7% ROIC providing clinical trial services to global pharma and biotech. Icon is one of the world's largest CROs — a quality outsourcing partner for drug development with consistent demand from growing pharma R&D spending.", ["Clinical trial management, data management and regulatory services for pharma and biotech.", "One of the largest CROs globally — deep pharma and biotech client relationships.", "Structural demand from growing pharmaceutical R&D outsourcing provides consistent revenue.", "EPS growing 3.8% annualised with consistent CRO demand from drug development pipeline."]),
    693: ('Linedata Services SA', 'French investment management software. High ROIC.', 'Investment software specialist.', "Linedata provides software solutions for the investment management and credit industries — front-to-back office platforms for asset managers and loan servicers. The company software is deeply embedded in investment workflows creating high switching costs.", 'Investment software. High ROIC compounder.', 'Asset management software compounder.', "A French investment management software company with a 13.8% ROIC and consistent recurring revenue. Linedata front-to-back office software is deeply embedded in asset manager operations — high switching costs from mission-critical investment workflow integration.", ["Front-to-back office software for asset managers and loan servicers globally.", "ROIC of 13.8% reflects consistent returns from embedded investment management software.", "EPS grew 11.1% annualised with consistent software subscription and maintenance revenue.", "Deep workflow integration creates high switching costs and durable client relationships."]),
    694: ('MAX Automation SE', 'German industrial automation. Contrarian recovery.', 'Industrial automation recovery.', "MAX Automation is a German industrial automation company producing assembly systems, robotics, and process automation solutions for automotive, medical, and electronics manufacturers. The company has been beaten down — fundamentals improving as industrial automation investment recovers.", 'Industrial automation. Contrarian recovery.', 'Automation recovery play.', "A German industrial automation company in a contrarian recovery phase. MAX Automation produces assembly and robotic systems for automotive and medical manufacturers — quality automation business trading below fair value as industrial capital expenditure recovers.", ["Assembly systems, robotics and process automation for automotive and medical industries.", "Recovery play as industrial automation investment normalises from a depressed period.", "EPS grew 15.1% annualised from a low base as automation demand and margins recovered.", "Contrarian entry as market discounts temporary industrial capex slowdown."]),
    695: ('Neurones', 'French IT services. High ROIC. Contrarian entry.', 'French IT quality play.', "Neurones is a French IT services company with exceptional ROIC from specialist consulting and infrastructure services to large French corporations. The company has been beaten down on sector concerns — quality business at a contrarian entry point.", 'French IT services. Contrarian quality entry.', 'IT quality contrarian compounder.', "A French IT services company with a 28.1% ROIC in a contrarian entry phase. Neurones specialist IT consulting generates exceptional returns — quality business at a discount to fair value as French IT sector concerns create a buying opportunity.", ["IT consulting and infrastructure services for large French corporations.", "ROIC of 28.1% — exceptional returns from specialist IT services positioning.", "EPS grew 10.5% annualised with consistent margin improvement from scale and specialisation.", "Contrarian entry as French IT sector sentiment creates discount to intrinsic value."]),
    697: ('Payoneer Global Inc', 'US cross-border payments platform. High ROIC.', 'Cross-border payments compounder.', "Payoneer is a US financial technology company enabling cross-border payments for businesses and freelancers globally. The platform connects sellers on marketplaces like Amazon and Upwork with their earnings across 190+ countries and currencies.", 'Cross-border payments. High ROIC growth.', 'Global payments compounder.', "A US cross-border payments platform with a 16.0% ROIC and EPS growth of 37.2% annualised. Payoneer enables global marketplace sellers and freelancers to receive and manage payments across 190+ countries — growing with the structural expansion of global digital commerce.", ["Cross-border payment platform for marketplace sellers and freelancers globally.", "ROIC of 16.0% reflects strong returns from the global payments network.", "EPS grew 37.2% annualised as cross-border digital commerce and freelance platforms expanded.", "Revenue grew 13.9% annualised with consistent customer growth and transaction volume expansion."]),
    698: ('QuinStreet Inc', 'US performance marketing. Contrarian value.', 'Performance marketing value play.', "QuinStreet operates vertical performance marketing platforms for insurance and financial services. The company has been beaten down — quality performance marketing business trading below fair value as insurance carrier advertising normalises from peak levels.", 'Performance marketing. Contrarian value.', 'Digital marketing contrarian.', "A US performance marketing company with a 29.9% ROIC in a contrarian value phase. QuinStreet vertical insurance and financial media platforms generate consistent performance fee revenue — quality business at a discount as insurance advertising cycle normalises.", ["Performance marketing for insurance, financial services and home services verticals.", "ROIC of 29.9% reflects strong returns from a capital-light performance fee model.", "EPS grew 19.9% annualised as vertical media traffic and conversion rates improved.", "Contrarian entry as insurance carrier advertising normalisation creates buying opportunity."]),
    699: ('Revenio', 'Finnish ophthalmology diagnostics. High ROIC.', 'Ophthalmic diagnostics specialist.', "Revenio is a Finnish company producing iCare tonometers — devices that measure intraocular eye pressure for glaucoma screening and monitoring. The company has a strong global market position in portable tonometry — growing with rising glaucoma awareness and diagnosis rates.", 'Ophthalmic diagnostics. High ROIC.', 'Eye diagnostics compounder.', "A Finnish ophthalmic diagnostics company with a 17.5% ROIC producing iCare tonometers for glaucoma screening. Revenio portable tonometry devices are used globally by ophthalmologists and optometrists — growing with increasing glaucoma diagnosis rates in ageing populations.", ["iCare tonometers for intraocular pressure measurement and glaucoma screening globally.", "ROIC of 17.5% reflects consistent returns from proprietary ophthalmic diagnostic technology.", "EPS grew 2.9% annualised with consistent tonometer sales and consumable revenue.", "Revenue grew 6.0% annualised as global glaucoma awareness and diagnosis rates expanded."]),
    700: ('Sage Group PLC', 'UK accounting software giant. High ROIC.', 'Accounting software compounder.', "Sage Group is a UK provider of accounting, payroll, and HR software for small and medium businesses globally. The company is transitioning its customer base to cloud subscriptions — building recurring revenue from a large installed base of SMB accounting software users.", 'Accounting software. High ROIC growth.', 'SMB accounting compounder.', "A UK accounting software company with an 18.8% ROIC and EPS growth of 5.9% annualised. Sage Group provides accounting and payroll software to millions of SMBs globally — transitioning to cloud subscriptions with high switching costs from deep financial workflow integration.", ["Accounting, payroll and HR software for small and medium businesses globally.", "ROIC of 18.8% reflects consistent returns from sticky SMB accounting software.", "EPS grew 5.9% annualised with consistent cloud subscription migration and new customer growth.", "Revenue grew 7.8% annualised as cloud transition and SMB software adoption expanded."]),
    701: ('Sidetrade SA', 'French AI accounts receivable software. High ROIC.', 'AI accounts receivable platform.', "Sidetrade is a French AI-powered accounts receivable and cash flow management software company. The platform automates invoice chasing, cash collection, and dispute resolution for enterprise finance teams — reducing days sales outstanding and improving working capital.", 'AI cash collection software. High ROIC.', 'AI fintech compounder.', "A French AI accounts receivable software company with a 31.2% ROIC and EPS growth of 18.8% annualised. Sidetrade AI platform automates cash collection for enterprise finance teams — exceptional returns from a SaaS model addressing a large and growing accounts receivable automation market.", ["AI-powered accounts receivable and cash collection software for enterprise finance.", "ROIC of 31.2% — exceptional returns from an asset-light AI SaaS platform.", "EPS grew 18.8% annualised as enterprise cash collection automation adoption expanded.", "Revenue grew 23.2% annualised with consistent enterprise customer additions and expansion."]),
    704: ('Tecsys Inc', 'Canadian supply chain software. High ROIC.', 'Supply chain SaaS compounder.', "Tecsys is a Canadian supply chain management software company serving health systems, hospitals, and complex distributors. The company cloud platform manages inventory, warehouse, and distribution operations — a mission-critical SaaS with high switching costs.", 'Supply chain software. High ROIC.', 'Healthcare supply chain compounder.', "A Canadian supply chain software company with a 15.8% ROIC providing mission-critical warehouse and distribution management. Tecsys serves hospitals and health systems — deeply embedded supply chain software with high switching costs and growing cloud subscription revenue.", ["Supply chain management software for health systems, hospitals and complex distributors.", "ROIC of 15.8% reflects consistent returns from mission-critical supply chain SaaS.", "EPS improving as cloud subscription transition builds recurring revenue base.", "Revenue grew 9.1% annualised with consistent healthcare supply chain software adoption."]),
    707: ('Vitec Software', 'Swedish vertical market software. High ROIC.', 'Vertical market software compounder.', "Vitec Software acquires and develops vertical market software for niche industries across Scandinavia and Europe. The company builds a portfolio of specialist software businesses serving specific industries — a compounding acquisition model generating consistent returns.", 'Vertical software acquisitions. High ROIC.', 'Vertical software compounder.', "A Swedish vertical market software company with a 5.2% ROIC building a portfolio of niche industry software businesses. Vitec acquires specialist software for specific industries — a proven acquisition-led compounding model with consistent long-term earnings growth.", ["Vertical market software for niche industries across Scandinavia and Europe.", "Acquisition-led model building portfolio of specialist software businesses.", "EPS grew 17.1% annualised with consistent acquisitions and organic growth.", "Revenue grew 9.0% annualised as vertical software portfolio expanded through acquisitions."]),
    708: ('Vtex', 'Brazilian e-commerce platform. High ROIC.', 'Latin American e-commerce platform.', "VTEX is a Brazilian enterprise e-commerce platform serving major retailers and brands across Latin America and globally. The company cloud commerce platform enables omnichannel retail — serving enterprise clients including Walmart, Motorola, and major Latin American retailers.", 'Enterprise e-commerce. High ROIC growth.', 'E-commerce platform compounder.', "A Brazilian enterprise e-commerce platform with a 30.1% ROIC and EPS growth of 89.1% annualised. VTEX serves major enterprise retailers globally with cloud commerce infrastructure — a scalable SaaS platform with high switching costs from deep retail system integration.", ["Enterprise e-commerce platform for major retailers and brands globally.", "ROIC of 30.1% — strong returns from an asset-light enterprise SaaS commerce model.", "EPS grew 89.1% annualised as enterprise e-commerce platform adoption expanded.", "Revenue grew 6.1% annualised with consistent enterprise client additions and GMV growth."]),
}
with open(CARDS_PATH, "r", encoding="utf-8") as f:
    content = f.read()
updated = 0
for card_id, (company, tag, tagBold, tagFull, pick, pickBold, pickFull, bullets) in descriptions.items():
    pattern = re.compile(rf"(id: {card_id}, type: .TWO..*?tag: ')[^']*('..*?tagBold: ')[^']*('..*?tagFull: \")[^\"]*(\",.*?pick: ')[^']*('..*?pickBold: ')[^']*('..*?pickFull: \")[^\"]*(\",)", re.DOTALL)
    replacement = rf"\g<1>{tag}\g<2>{tagBold}\g<3>{tagFull}\g<4>{pick}\g<5>{pickBold}\g<6>{pickFull}\g<7>"
    new_content = pattern.sub(replacement, content)
    if new_content != content:
        content = new_content
        updated += 1
        print(f"OK {card_id}: {company}")
    else:
        print(f"MISS {card_id}: {company}")
    bullets_str = ", ".join([f'"{b}"' for b in bullets])
    bp = re.compile(rf"(id: {card_id},.*?bullets: \[)[^\]]*\]", re.DOTALL)
    content = bp.sub(rf"\g<1>{bullets_str}]", content)
with open(CARDS_PATH, "w", encoding="utf-8") as f:
    f.write(content)
print(f"Updated: {updated}")
print(f"Remaining: {content.count('operates in')}")
